package bead

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

// DoctorFinding reports a single field that exceeds MaxFieldBytes on a single
// bead row. One bead can produce multiple findings (description + acceptance
// + event bodies, etc.).
type DoctorFinding struct {
	BeadID     string
	FieldPath  string // "description", "acceptance", "notes", "events[N].body", "events[N].summary"
	SizeBytes  int
	SampleHead string // first 80 bytes for visual identification
}

// DoctorReport is the output of BeadDoctor — an ordered list of findings.
type DoctorReport struct {
	Path     string
	Findings []DoctorFinding
}

// Clean is true when there are no findings (i.e. all bead fields fit).
func (r DoctorReport) Clean() bool { return len(r.Findings) == 0 }

// BeadDoctor scans a beads.jsonl file and returns every field that exceeds
// MaxFieldBytes. Parses each line best-effort; lines that fail to parse are
// reported as a single finding with FieldPath="line" and the raw line as the
// sample.
func BeadDoctor(path string) (DoctorReport, error) {
	report := DoctorReport{Path: path}
	f, err := os.Open(path)
	if err != nil {
		return report, err
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
	lineNo := 0
	for scanner.Scan() {
		lineNo++
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var raw map[string]any
		if err := json.Unmarshal(line, &raw); err != nil {
			report.Findings = append(report.Findings, DoctorFinding{
				BeadID:     fmt.Sprintf("line %d (unparseable)", lineNo),
				FieldPath:  "line",
				SizeBytes:  len(line),
				SampleHead: firstN(string(line), 80),
			})
			continue
		}
		id, _ := raw["id"].(string)
		for _, field := range []string{"description", "acceptance", "notes"} {
			if s, ok := raw[field].(string); ok && len(s) > MaxFieldBytes {
				report.Findings = append(report.Findings, DoctorFinding{
					BeadID:     id,
					FieldPath:  field,
					SizeBytes:  len(s),
					SampleHead: firstN(s, 80),
				})
			}
		}
		if events, ok := raw["events"].([]any); ok {
			for i, evRaw := range events {
				ev, _ := evRaw.(map[string]any)
				if ev == nil {
					continue
				}
				for _, field := range []string{"body", "summary"} {
					if s, ok := ev[field].(string); ok && len(s) > MaxFieldBytes {
						report.Findings = append(report.Findings, DoctorFinding{
							BeadID:     id,
							FieldPath:  fmt.Sprintf("events[%d].%s", i, field),
							SizeBytes:  len(s),
							SampleHead: firstN(s, 80),
						})
					}
				}
			}
		}
	}
	if err := scanner.Err(); err != nil {
		return report, fmt.Errorf("bead doctor: scanner: %w", err)
	}
	sort.SliceStable(report.Findings, func(i, j int) bool {
		if report.Findings[i].BeadID == report.Findings[j].BeadID {
			return report.Findings[i].FieldPath < report.Findings[j].FieldPath
		}
		return report.Findings[i].BeadID < report.Findings[j].BeadID
	})
	return report, nil
}

// BeadDoctorFix rewrites oversized fields on disk. Behavior:
//
//  1. If the file is already clean, returns the empty report without
//     touching anything.
//  2. Otherwise writes a timestamped backup under .ddx/backups/ before any
//     mutation; errors if the backup write fails.
//  3. Truncates oversized fields via capFieldBytes (head+tail+marker), then
//     writes full overflow content to
//     .ddx/executions/<bead-id>/repair-<timestamp>/<field>.log so the
//     original payload remains auditable.
//  4. Appends a repair event to each rewritten bead (kind="repair", actor=
//     "ddx bead doctor").
//  5. Returns the report of findings that were remediated.
//
// Idempotent: a second call finds no offending fields and returns a clean
// report without writing anything.
func BeadDoctorFix(path string, now func() time.Time) (DoctorReport, error) {
	if now == nil {
		now = time.Now
	}
	report, err := BeadDoctor(path)
	if err != nil {
		return report, err
	}
	if report.Clean() {
		return report, nil
	}

	ddxDir := filepath.Dir(path)
	ts := now().UTC().Format("20060102T150405")

	backupDir := filepath.Join(ddxDir, "backups")
	if err := os.MkdirAll(backupDir, 0o755); err != nil {
		return report, fmt.Errorf("bead doctor: mkdir backup dir: %w", err)
	}
	backupPath := filepath.Join(backupDir, fmt.Sprintf("beads-%s.jsonl", ts))
	src, err := os.ReadFile(path)
	if err != nil {
		return report, fmt.Errorf("bead doctor: read source: %w", err)
	}
	if err := os.WriteFile(backupPath, src, 0o644); err != nil {
		return report, fmt.Errorf("bead doctor: write backup %s: %w", backupPath, err)
	}

	// Per-bead rewrite: parse each line, repair it, write it back.
	findingsByBead := make(map[string][]DoctorFinding)
	for _, f := range report.Findings {
		findingsByBead[f.BeadID] = append(findingsByBead[f.BeadID], f)
	}

	lines := bytes.Split(src, []byte{'\n'})
	var out bytes.Buffer
	for _, line := range lines {
		trimmed := bytes.TrimSpace(line)
		if len(trimmed) == 0 {
			out.Write(line)
			out.WriteByte('\n')
			continue
		}
		var raw map[string]any
		if err := json.Unmarshal(trimmed, &raw); err != nil {
			// Leave unparseable lines alone; the doctor report flagged them
			// but we cannot safely rewrite what we cannot parse.
			out.Write(line)
			out.WriteByte('\n')
			continue
		}
		id, _ := raw["id"].(string)
		beadFindings := findingsByBead[id]
		if len(beadFindings) == 0 {
			out.Write(trimmed)
			out.WriteByte('\n')
			continue
		}

		repairDir := filepath.Join(ddxDir, "executions", id, "repair-"+ts)
		if err := os.MkdirAll(repairDir, 0o755); err != nil {
			return report, fmt.Errorf("bead doctor: mkdir repair dir for %s: %w", id, err)
		}
		repaired := repairBead(raw, beadFindings, repairDir, ddxDir, now().UTC())
		encoded, err := json.Marshal(repaired)
		if err != nil {
			return report, fmt.Errorf("bead doctor: re-encode %s: %w", id, err)
		}
		out.Write(encoded)
		out.WriteByte('\n')
	}

	// Trim trailing newline if the source didn't have one.
	written := out.Bytes()
	if !bytes.HasSuffix(src, []byte{'\n'}) && bytes.HasSuffix(written, []byte{'\n'}) {
		written = written[:len(written)-1]
	}

	if err := os.WriteFile(path, written, 0o644); err != nil {
		return report, fmt.Errorf("bead doctor: write repaired %s: %w", path, err)
	}
	return report, nil
}

// repairBead applies per-field truncation + artifact sidecar writes. Updates
// raw in place and returns it for convenience.
func repairBead(raw map[string]any, findings []DoctorFinding, repairDir, ddxDir string, ts time.Time) map[string]any {
	artifactRefs := make([]string, 0, len(findings))
	for _, f := range findings {
		ref := applyFieldRepair(raw, f, repairDir, ddxDir)
		if ref != "" {
			artifactRefs = append(artifactRefs, f.FieldPath+"→"+ref)
		}
	}

	if len(artifactRefs) == 0 {
		return raw
	}

	events, _ := raw["events"].([]any)
	events = append(events, map[string]any{
		"kind":       "repair",
		"summary":    fmt.Sprintf("field cap (%d bytes) enforced: %d field(s) truncated", MaxFieldBytes, len(artifactRefs)),
		"body":       strings.Join(artifactRefs, "\n"),
		"actor":      "ddx bead doctor",
		"source":     "ddx bead doctor --fix",
		"created_at": ts.Format(time.RFC3339Nano),
	})
	raw["events"] = events
	raw["updated_at"] = ts.Format(time.RFC3339Nano)
	return raw
}

// applyFieldRepair replaces raw[field] with a capped version and writes the
// full content to an artifact path. Returns the repair-relative artifact
// path (for the repair event summary) or "" if the path cannot be resolved.
func applyFieldRepair(raw map[string]any, f DoctorFinding, repairDir, ddxDir string) string {
	original, ok := pickField(raw, f.FieldPath)
	if !ok {
		return ""
	}
	artifactName := strings.ReplaceAll(f.FieldPath, "[", "_")
	artifactName = strings.ReplaceAll(artifactName, "]", "")
	artifactName = strings.ReplaceAll(artifactName, ".", "_") + ".log"
	artifactPath := filepath.Join(repairDir, artifactName)
	if err := os.WriteFile(artifactPath, []byte(original), 0o644); err != nil {
		return ""
	}
	rel, err := filepath.Rel(filepath.Dir(ddxDir), artifactPath)
	if err != nil {
		rel = artifactPath
	}
	// capFieldBytes already yields a value at or below MaxFieldBytes. Don't
	// append the artifact reference to the field itself — that would push it
	// back over the cap and defeat idempotency. The repair event body
	// records the field→artifact mapping for audit.
	setField(raw, f.FieldPath, capFieldBytes(original))
	return rel

package cmd

import (
	"encoding/json"
	"fmt"
	"path/filepath"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/spf13/cobra"
)

// newBeadDoctorCommand wires `ddx bead doctor` / `ddx bead doctor --fix`.
//
// Scan mode (no flags): exits non-zero if any field on any bead exceeds the
// per-field cap (ddx-f8a11202), reporting the offending bead id, field, and
// size. Safe to run on any tree — no mutations.
//
// Fix mode (--fix): rewrites oversized fields in place. Before touching the
// tracker the command writes a timestamped backup under .ddx/backups/ so
// the original file is always recoverable. Overflow content persists as
// artifacts under .ddx/executions/<bead-id>/repair-<timestamp>/ and a
// repair event is appended to each rewritten bead. Idempotent — the second
// invocation exits 0 without writing because the scan is clean.
//
// Dangling-success mode (--dangling): detects in_progress beads whose last
// execution produced task_succeeded but CloseWithEvidence never ran. Safe
// to run on any tree — no mutations unless --fix is also passed.
// (ddx-2b2d114e)
func (f *CommandFactory) newBeadDoctorCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "doctor",
		Short: "Detect (and optionally repair) beads.jsonl rows with oversized fields",
		Long: `Scan the bead tracker for fields that exceed the per-field size cap.

Bead fields (description, acceptance, notes, events[].body, events[].summary)
are capped at 65,535 bytes so DDx-authored beads round-trip cleanly through
bd import (upstream's Dolt TEXT column limit). Fields over the cap usually
come from a writer bug that landed before the cap was enforced — for
example a reviewer stream dumped verbatim into an event body.

Without --fix this command only reports offending rows and exits non-zero.
With --fix it:

  1. Writes a timestamped backup to .ddx/backups/ before any mutation.
  2. Truncates each oversized field to the cap using head+tail+marker.
  3. Writes the full original payload to
     .ddx/executions/<bead>/repair-<timestamp>/<field>.log so forensics
     remain possible.
  4. Appends a kind=repair event to every rewritten bead.

Idempotent: once a tracker is clean, running --fix again is a no-op.

With --dangling: scan for in_progress beads whose last execution produced
task_succeeded but whose bead-close step never ran (dangling-success).
For each finding, reports whether result_rev is reachable from HEAD:
  - reachable=true:  merge succeeded, close didn't. Safe to close manually
    with: ddx bead close <bead-id>
  - reachable=false: the merge itself was never applied (dangling commit).
    The result_rev is shown for manual git cherry-pick or re-attempt.
(ddx-2b2d114e)`,
		RunE: func(cmd *cobra.Command, args []string) error {
			workspace := f.beadWorkspaceRoot()
			if workspace == "" {
				return fmt.Errorf("bead doctor: no .ddx workspace found")
			}
			path := ddxroot.JoinProject(workspace, "beads.jsonl")

			doFix, _ := cmd.Flags().GetBool("fix")
			asJSON, _ := cmd.Flags().GetBool("json")
			doDangling, _ := cmd.Flags().GetBool("dangling")

			// --dangling mode: detect dangling-success beads (ddx-2b2d114e).
			if doDangling {
				findings, err := agent.DetectDanglingSuccessBeads(workspace)
				if err != nil {
					return fmt.Errorf("bead doctor --dangling: %w", err)
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(struct {
						Clean    bool                           `json:"clean"`
						Findings []agent.DanglingSuccessFinding `json:"findings"`
					}{
						Clean:    len(findings) == 0,
						Findings: findings,
					})
				}
				out := cmd.OutOrStdout()
				if len(findings) == 0 {
					fmt.Fprintf(out, "bead doctor --dangling: clean (no dangling-success beads detected)\n")
					return nil
				}
				fmt.Fprintf(out, "bead doctor --dangling: %d finding(s):\n", len(findings))
				for _, fi := range findings {
					reachableStr := "reachable=false (dangling commit — merge never applied)"
					recovery := "  recovery: git cherry-pick or re-run ddx try " + fi.BeadID
					if fi.Reachable {
						reachableStr = "reachable=true (merge succeeded, close didn't run)"
						recovery = "  recovery: ddx bead close " + fi.BeadID + "  # or re-run ddx try"
					}
					fmt.Fprintf(out, "  %s  attempt=%s  result_rev=%s\n    %s\n%s\n",
						fi.BeadID, fi.AttemptID, fi.ResultRev, reachableStr, recovery)
				}
				return fmt.Errorf("bead doctor --dangling: %d finding(s) detected", len(findings))
			}

			var report bead.DoctorReport
			var err error
			if doFix {
				report, err = bead.BeadDoctorFix(path, nil)
			} else {
				report, err = bead.BeadDoctor(path)
			}
			if err != nil {
				return err
			}

			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(struct {
					Path     string               `json:"path"`
					Fixed    bool                 `json:"fixed"`
					Clean    bool                 `json:"clean"`
					Findings []bead.DoctorFinding `json:"findings"`
				}{
					Path:     report.Path,
					Fixed:    doFix && !report.Clean(),
					Clean:    report.Clean(),
					Findings: report.Findings,
				})
			}

			out := cmd.OutOrStdout()
			if report.Clean() {
				fmt.Fprintf(out, "bead doctor: %s — clean (no fields exceed %d bytes)\n", path, bead.MaxFieldBytes)
				return nil
			}
			fmt.Fprintf(out, "bead doctor: %s — %d finding(s) exceeding %d-byte cap:\n", path, len(report.Findings), bead.MaxFieldBytes)
			for _, f := range report.Findings {
				fmt.Fprintf(out, "  %s  %s  %d bytes  head=%q\n", f.BeadID, f.FieldPath, f.SizeBytes, f.SampleHead)
			}
			if doFix {
				fmt.Fprintf(out, "\nrepair complete. backup written to %s/backups/. artifact sidecars under %s/executions/<bead>/repair-*/\n", filepath.Dir(path), filepath.Dir(path))
				return nil
			}
			// Non-fix scan: non-zero exit via cobra error so CI can catch it.
			return fmt.Errorf("bead doctor: %d finding(s) — run `ddx bead doctor --fix` to repair", len(report.Findings))
		},
	}
	cmd.Flags().Bool("fix", false, "Rewrite oversized fields in place after writing a backup")
	cmd.Flags().Bool("json", false, "Output findings as JSON")
	cmd.Flags().Bool("dangling", false, "Detect in_progress beads with a prior task_succeeded result (dangling-success, ddx-2b2d114e)")
	return cmd
}

package bead

import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestBeadDoctor_CleanFileReportsNothing covers ddx-b695e162 AC #1: a
// beads.jsonl whose fields all fit under MaxFieldBytes produces a clean
// report. The scan must be a no-op on healthy trees — false positives here
// would spam every operator's CI.
func TestBeadDoctor_CleanFileReportsNothing(t *testing.T) {
	path := filepath.Join(t.TempDir(), "beads.jsonl")
	line := `{"id":"ddx-ok","title":"fine","type":"task","status":"open","priority":2,"description":"normal","labels":[],"deps":[],"created_at":"2026-01-01T00:00:00Z","updated_at":"2026-01-01T00:00:00Z"}`
	require.NoError(t, os.WriteFile(path, []byte(line+"\n"), 0o644))

	report, err := BeadDoctor(path)
	require.NoError(t, err)
	assert.True(t, report.Clean())
	assert.Empty(t, report.Findings)
}

// TestBeadDoctor_DetectsOversizedFields covers ddx-b695e162 AC #1: scanner
// reports every field on every bead that exceeds the cap. Synthesizes a
// description longer than MaxFieldBytes and an event body ditto so both
// code paths (top-level fields + nested event fields) are exercised.
func TestBeadDoctor_DetectsOversizedFields(t *testing.T) {
	path := filepath.Join(t.TempDir(), "beads.jsonl")
	huge := strings.Repeat("x", MaxFieldBytes+100)
	bead := map[string]any{
		"id":          "ddx-oversized",
		"title":       "oversized",
		"type":        "task",
		"status":      "open",
		"priority":    2,
		"description": huge,
		"labels":      []string{},
		"deps":        []string{},
		"events": []any{
			map[string]any{"kind": "review", "summary": "APPROVE", "body": huge},
		},
		"created_at": "2026-01-01T00:00:00Z",
		"updated_at": "2026-01-01T00:00:00Z",
	}
	encoded, err := json.Marshal(bead)
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(path, append(encoded, '\n'), 0o644))

	report, err := BeadDoctor(path)
	require.NoError(t, err)
	require.Len(t, report.Findings, 2, "both description and events[0].body must be flagged — partial detection would hide the tracker-corruption surface")

	paths := []string{report.Findings[0].FieldPath, report.Findings[1].FieldPath}
	assert.Contains(t, paths, "description")
	assert.Contains(t, paths, "events[0].body")
	for _, f := range report.Findings {
		assert.Equal(t, "ddx-oversized", f.BeadID)
		assert.Greater(t, f.SizeBytes, MaxFieldBytes, "reported size must exceed the cap — the whole point of the finding")
	}
}

// TestBeadDoctorFix_RewriteIsIdempotent covers ddx-b695e162 AC #3: a tree
// that has been repaired stays clean on subsequent --fix runs. Non-idempotent
// repair would re-process the already-capped field and accumulate artifact
// sidecars on every run.
func TestBeadDoctorFix_RewriteIsIdempotent(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")

	huge := strings.Repeat("A", MaxFieldBytes+10)
	bead := map[string]any{
		"id":          "ddx-fix-idempotent",
		"title":       "fix me",
		"type":        "task",
		"status":      "open",
		"priority":    2,
		"description": huge,
		"labels":      []string{},
		"deps":        []string{},
		"created_at":  "2026-01-01T00:00:00Z",
		"updated_at":  "2026-01-01T00:00:00Z",
	}
	encoded, err := json.Marshal(bead)
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(path, append(encoded, '\n'), 0o644))

	fixedAt := time.Date(2026, 4, 20, 12, 0, 0, 0, time.UTC)
	report1, err := BeadDoctorFix(path, func() time.Time { return fixedAt })
	require.NoError(t, err)
	require.False(t, report1.Clean(), "first fix must find the oversized field")

	report2, err := BeadDoctorFix(path, func() time.Time { return fixedAt.Add(time.Hour) })
	require.NoError(t, err)
	assert.True(t, report2.Clean(), "after a --fix pass the tree must be clean so repeated runs do not re-repair the same rows")
}

// TestBeadDoctorFix_WritesBackupAndArtifact covers ddx-b695e162 AC #2: a
// --fix run writes a backup before touching the source and persists full
// overflow content as an artifact sidecar. Operators MUST be able to recover
// the pre-fix state and audit the truncated payload.
func TestBeadDoctorFix_WritesBackupAndArtifact(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")

	huge := strings.Repeat("B", MaxFieldBytes+100)
	bead := map[string]any{
		"id":          "ddx-artifact-test",
		"title":       "with artifact",
		"type":        "task",
		"status":      "open",
		"priority":    2,
		"description": huge,
		"labels":      []string{},
		"deps":        []string{},
		"created_at":  "2026-01-01T00:00:00Z",
		"updated_at":  "2026-01-01T00:00:00Z",
	}
	encoded, err := json.Marshal(bead)
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(path, append(encoded, '\n'), 0o644))

	fixedAt := time.Date(2026, 4, 20, 12, 0, 0, 0, time.UTC)
	_, err = BeadDoctorFix(path, func() time.Time { return fixedAt })
	require.NoError(t, err)

	// Backup exists with the original huge content intact.
	backups, err := os.ReadDir(filepath.Join(ddxDir, "backups"))
	require.NoError(t, err)
	require.Len(t, backups, 1, "exactly one backup must be written per --fix invocation")
	backupContents, err := os.ReadFile(filepath.Join(ddxDir, "backups", backups[0].Name()))
	require.NoError(t, err)
	assert.Contains(t, string(backupContents), huge[:200],
		"backup must preserve the pre-fix payload byte-for-byte — otherwise recovery is impossible")

	// Artifact sidecar holds the full original field.
	artifactDir := filepath.Join(ddxDir, "executions", "ddx-artifact-test", "repair-20260420T120000")
	entries, err := os.ReadDir(artifactDir)
	require.NoError(t, err, "repair dir must be created per bead per --fix invocation")
	require.Len(t, entries, 1, "one sidecar per oversized field")
	artifactContents, err := os.ReadFile(filepath.Join(artifactDir, entries[0].Name()))
	require.NoError(t, err)
	assert.Equal(t, huge, string(artifactContents),
		"sidecar must preserve the original oversized field verbatim — this is the forensic trail that makes truncation safe")

	// Repaired source has a repair event recording what was done.
	repaired, err := os.ReadFile(path)
	require.NoError(t, err)
	var parsed map[string]any
	require.NoError(t, json.Unmarshal(repaired, &parsed))
	events, ok := parsed["events"].([]any)
	require.True(t, ok, "repair event must be appended to the rewritten bead")
	require.Len(t, events, 1)
	ev := events[0].(map[string]any)
	assert.Equal(t, "repair", ev["kind"])
	assert.Equal(t, "ddx bead doctor", ev["actor"])
	assert.Contains(t, ev["body"], "description",
		"repair event body must name the repaired field so operator audit can correlate")
}

// TestBeadDoctorFix_OversizedLineFromFixture covers ddx-b695e162 AC #4 using
// the byte-frozen fixture from ddx-004eccbc. A fixture captured from a real
// 2026-04-18 incident (axon's oversized beads.jsonl row) must be
// re-readable by the doctor and repairable — proving the whole pipeline
// works against a non-synthesized case.
func TestBeadDoctorFix_OversizedLineFromFixture(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")

	// Use the ddx-004eccbc fixture. The fixture is a single bead row; doctor
	// should either (a) flag one or more oversized fields and repair them, or
	// (b) decide the row is unparseable and flag line-level. Either outcome
	// is acceptable — the invariant is "doctor does not crash, and the file
	// is parseable afterward."
	fixtureCandidates := []string{
		"../agent/testdata/reviewer/bead-jsonl-oversized-line.jsonl",
		"../../internal/agent/testdata/reviewer/bead-jsonl-oversized-line.jsonl",
	}
	var fixtureBytes []byte
	for _, p := range fixtureCandidates {
		if b, err := os.ReadFile(p); err == nil {
			fixtureBytes = b
			break
		}
	}
	if len(fixtureBytes) == 0 {
		t.Skip("ddx-004eccbc fixture not present at expected path; skip")
	}
	require.NoError(t, os.WriteFile(path, fixtureBytes, 0o644))

	fixedAt := time.Date(2026, 4, 20, 12, 0, 0, 0, time.UTC)
	_, err := BeadDoctorFix(path, func() time.Time { return fixedAt })
	require.NoError(t, err, "doctor must not crash on the real-incident fixture")

	// After repair the tree must be clean.
	report, err := BeadDoctor(path)
	require.NoError(t, err)
	assert.True(t, report.Clean(),
		"post-repair scan must find no remaining oversized fields — otherwise the repair didn't actually address the finding")
}

