291			return report, fmt.Errorf("bead doctor: read source: %w", err)
292		}
293		if err := os.WriteFile(backupPath, src, 0o644); err != nil {
294			return report, fmt.Errorf("bead doctor: write backup %s: %w", backupPath, err)
295		}
296	
297		// Per-bead rewrite: parse each line, repair it, write it back.
298		findingsByBead := make(map[string][]DoctorFinding)
299		for _, f := range report.Findings {
300			findingsByBead[f.BeadID] = append(findingsByBead[f.BeadID], f)

300			findingsByBead[f.BeadID] = append(findingsByBead[f.BeadID], f)
301		}
302	
303		lines := bytes.Split(src, []byte{'\n'})
304		var out bytes.Buffer
305		for _, line := range lines {
306			trimmed := bytes.TrimSpace(line)
307			if len(trimmed) == 0 {
308				out.Write(line)
309				out.WriteByte('\n')
310				continue
311			}
312			var raw map[string]any
313			if err := json.Unmarshal(trimmed, &raw); err != nil {
314				// Leave unparseable lines alone; the doctor report flagged them
315				// but we cannot safely rewrite what we cannot parse.
316				out.Write(line)
317				out.WriteByte('\n')
318				continue
319			}
320			id, _ := raw["id"].(string)
321			beadFindings := findingsByBead[id]
322			if len(beadFindings) == 0 {
323				out.Write(trimmed)
324				out.WriteByte('\n')
325				continue
326			}
327	
328			repairDir := filepath.Join(ddxDir, "executions", id, "repair-"+ts)
329			if err := os.MkdirAll(repairDir, 0o755); err != nil {
330				return report, fmt.Errorf("bead doctor: mkdir repair dir for %s: %w", id, err)
331			}
332			repaired := repairBead(raw, beadFindings, repairDir, ddxDir, now().UTC())
333			encoded, err := json.Marshal(repaired)
334			if err != nil {
335				return report, fmt.Errorf("bead doctor: re-encode %s: %w", id, err)
336			}
337			out.Write(encoded)
338			out.WriteByte('\n')
339		}
340	
341		// Trim trailing newline if the source didn't have one.
342		written := out.Bytes()
343		if !bytes.HasSuffix(src, []byte{'\n'}) && bytes.HasSuffix(written, []byte{'\n'}) {
344			written = written[:len(written)-1]
345		}
346	
347		if err := os.WriteFile(path, written, 0o644); err != nil {
348			return report, fmt.Errorf("bead doctor: write repaired %s: %w", path, err)
349		}
350		return report, nil
351	}
