353	// repairBead applies per-field truncation and dependency edge removal.
354	// It updates raw in place and returns it for convenience.
355	func repairBead(raw map[string]any, findings []DoctorFinding, repairDir, ddxDir string, ts time.Time) map[string]any {
356		actionRefs := make([]string, 0, len(findings))
357		for _, f := range findings {
358			switch f.Code {
359			case DoctorFindingCodeFieldCapOverflow:
360				ref := applyFieldRepair(raw, f, repairDir, ddxDir)
361				if ref != "" {
362					actionRefs = append(actionRefs, f.FieldPath+"→"+ref)
363				}
364			case DoctorFindingCodeParentAncestorInDeps:
365				if applyDependencyRepair(raw, f) {
366					actionRefs = append(actionRefs, f.FieldPath+"→removed")
367				}
368			}
369		}
370	
371		if len(actionRefs) == 0 {
372			return raw
373		}
374	
375		events, _ := raw["events"].([]any)
376		events = append(events, map[string]any{
377			"kind":       "repair",
378			"summary":    fmt.Sprintf("doctor repair applied: %d mutation(s)", len(actionRefs)),
379			"body":       strings.Join(actionRefs, "\n"),
380			"actor":      "ddx bead doctor",

380			"actor":      "ddx bead doctor",
381			"source":     "ddx bead doctor --fix",
382			"created_at": ts.Format(time.RFC3339Nano),
383		})
384		raw["events"] = events
385		raw["updated_at"] = ts.Format(time.RFC3339Nano)
386		return raw
387	}
