389	func applyDependencyRepair(raw map[string]any, f DoctorFinding) bool {
390		field, idx, ok := parseDependencyFieldPath(f.FieldPath)
391		if !ok {
392			return false
393		}
394		switch field {
395		case doctorDependencyDepsField:
396			deps, ok := raw[doctorDependencyDepsField].([]any)
397			if !ok || idx < 0 || idx >= len(deps) {
398				return false
399			}
400			raw[doctorDependencyDepsField] = removeAnyIndex(deps, idx)
401			return true
402		case doctorDependencyDependenciesField:
403			deps, ok := raw[doctorDependencyDependenciesField].([]any)
404			if !ok || idx < 0 || idx >= len(deps) {
405				return false
406			}
407			raw[doctorDependencyDependenciesField] = removeAnyIndex(deps, idx)
408			return true
409		default:
410			return false
411		}
412	}
