414	// applyFieldRepair replaces raw[field] with a capped version and writes the
415	// full content to an artifact path. Returns the repair-relative artifact
416	// path (for the repair event summary) or "" if the path cannot be resolved.
417	func applyFieldRepair(raw map[string]any, f DoctorFinding, repairDir, ddxDir string) string {
418		original, ok := pickField(raw, f.FieldPath)
419		if !ok {
420			return ""
421		}
422		artifactName := strings.ReplaceAll(f.FieldPath, "[", "_")
423		artifactName = strings.ReplaceAll(artifactName, "]", "")
424		artifactName = strings.ReplaceAll(artifactName, ".", "_") + ".log"
425		artifactPath := filepath.Join(repairDir, artifactName)
426		if err := os.WriteFile(artifactPath, []byte(original), 0o644); err != nil {
427			return ""
428		}
429		rel, err := filepath.Rel(filepath.Dir(ddxDir), artifactPath)
430		if err != nil {
431			rel = artifactPath
432		}
433		// capFieldBytes already yields a value at or below MaxFieldBytes. Don't
434		// append the artifact reference to the field itself — that would push it
435		// back over the cap and defeat idempotency. The repair event body
436		// records the field→artifact mapping for audit.
437		setField(raw, f.FieldPath, capFieldBytes(original))
438		return rel
439	}
