441	// pickField reads raw[path] where path is either a flat key or
442	// "events[N].field".
443	func pickField(raw map[string]any, path string) (string, bool) {
444		if !strings.Contains(path, "events[") {
445			s, ok := raw[path].(string)
446			return s, ok
447		}
448		// events[N].field
449		openIdx := strings.Index(path, "[")
450		closeIdx := strings.Index(path, "]")
451		if openIdx < 0 || closeIdx < 0 {
452			return "", false
453		}
454		var n int
455		if _, err := fmt.Sscanf(path[openIdx+1:closeIdx], "%d", &n); err != nil {
456			return "", false
457		}
458		field := strings.TrimPrefix(path[closeIdx+1:], ".")
459		events, ok := raw["events"].([]any)
460		if !ok || n >= len(events) {
461			return "", false
462		}
463		ev, _ := events[n].(map[string]any)
464		if ev == nil {
465			return "", false
466		}
467		s, ok := ev[field].(string)
468		return s, ok
469	}
