353	// repairBead applies per-field truncation and dependency edge removal.
354	// It updates raw in place and returns it for convenience.
355	func repairBead(raw map[string]any, findings []DoctorFinding, repairDir, ddxDir string, ts time.Time) map[string]any {
356		actionRefs := make([]string, 0, len(findings))
357		depFindings := make([]DoctorFinding, 0, len(findings))
358		for _, f := range findings {
359			switch f.Code {
360			case DoctorFindingCodeFieldCapOverflow:
361				ref := applyFieldRepair(raw, f, repairDir, ddxDir)
362				if ref != "" {
363					actionRefs = append(actionRefs, f.FieldPath+"→"+ref)
364				}
365			case DoctorFindingCodeParentAncestorInDeps:
366				depFindings = append(depFindings, f)
367			}
368		}
369		if len(depFindings) > 0 {
370			actionRefs = append(actionRefs, applyDependencyRepairs(raw, depFindings)...)
371		}
372	
373		if len(actionRefs) == 0 {
374			return raw
375		}
376	
377		events, _ := raw["events"].([]any)
378		events = append(events, map[string]any{
379			"kind":       "repair",
380			"summary":    fmt.Sprintf("doctor repair applied: %d mutation(s)", len(actionRefs)),
381			"body":       strings.Join(actionRefs, "\n"),
382			"actor":      "ddx bead doctor",
383			"source":     "ddx bead doctor --fix",
384			"created_at": ts.Format(time.RFC3339Nano),
385		})
386		raw["events"] = events
387		raw["updated_at"] = ts.Format(time.RFC3339Nano)
388		return raw
389	}
