391	func applyDependencyRepairs(raw map[string]any, findings []DoctorFinding) []string {
392		type removalSet map[int]struct{}
393		removals := map[string]removalSet{
394			doctorDependencyDepsField:             {},
395			doctorDependencyDependenciesField:     {},
396		}
397		actionRefs := make([]string, 0, len(findings))
398		for _, f := range findings {
399			field, idx, ok := parseDependencyFieldPath(f.FieldPath)
400			if !ok {
401				continue
402			}
403			if removals[field] == nil {
404				removals[field] = make(removalSet)
405			}
406			removals[field][idx] = struct{}{}
407			actionRefs = append(actionRefs, f.FieldPath+"→removed")
408		}
409		if len(removals[doctorDependencyDepsField]) > 0 {
410			if deps, ok := raw[doctorDependencyDepsField].([]any); ok {
411				raw[doctorDependencyDepsField] = filterAnyIndex(deps, removals[doctorDependencyDepsField])
412			}
413		}
414		if len(removals[doctorDependencyDependenciesField]) > 0 {
415			if deps, ok := raw[doctorDependencyDependenciesField].([]any); ok {
416				raw[doctorDependencyDependenciesField] = filterAnyIndex(deps, removals[doctorDependencyDependenciesField])
417			}
418		}
419		return actionRefs
420	}
421	
422	func parseDependencyFieldPath(path string) (string, int, bool) {
423		openIdx := strings.Index(path, "[")
424		closeIdx := strings.Index(path, "]")
425		if openIdx <= 0 || closeIdx <= openIdx {
426			return "", 0, false
427		}
428		field := path[:openIdx]
429		if field != doctorDependencyDepsField && field != doctorDependencyDependenciesField {
430			return "", 0, false
